#[cfg(target_arch = "riscv64")]
core::arch::global_asm!(
    r#"
    .section .text.entry
    .globl _start
_start:
    la sp, boot_stack_top
    call rust_main

    .section .bss.stack
    .align 12
boot_stack:
    .space 4096 * 16
boot_stack_top:
    "#
);

#[cfg(target_arch = "riscv64")]
#[no_mangle]
pub extern "C" fn rust_main(hart_id: usize, dtb_paddr: usize) -> ! {
    kernel::arch::boot::seed(hart_id, dtb_paddr, kernel::arch::RawBootSource::DeviceTree);
    kernel::arch::cpu::set_current_id(hart_id);

    if hart_id != 0 {
        loop {
            kernel::arch::cpu::halt();
        }
    }

    kernel::arch::console::write_bytes(b"namenotfound qemu riscv64 boot\n");
    let _ = kernel::init_all();
    kernel::arch::console::write_bytes(b"init_all returned\n");
    kernel::run_current_user();
}

#[cfg(target_arch = "riscv64")]
#[panic_handler]
fn panic(_info: &core::panic::PanicInfo<'_>) -> ! {
    kernel::raw_panic()
}

#[cfg(not(target_arch = "riscv64"))]
fn main() {}

#![cfg_attr(target_arch = "loongarch64", no_std)]
#![cfg_attr(target_arch = "loongarch64", no_main)]

#[cfg(target_arch = "loongarch64")]
core::arch::global_asm!(
    r#"
    .section .boot.entry, "ax"
    .globl _start
_start:
    ori         $t0, $zero, 0x9
    lu52i.d     $t0, $t0, -2048
    csrwr       $t0, 0x180

    ori         $t0, $zero, 0x19
    lu52i.d     $t0, $t0, -1792
    csrwr       $t0, 0x181

    li.w        $t0, 0x08
    csrwr       $t0, 0x0
    move        $t0, $zero
    csrwr       $t0, 0x1

    li.w        $t0, 0x7
    csrwr       $t0, 0x2

    la.global   $sp, bootstacktop
    csrrd       $a0, 0x20
    la.global   $t0, rust_main
    jirl        $zero, $t0, 0
    "#
);

#[cfg(target_arch = "loongarch64")]
#[no_mangle]
pub extern "C" fn rust_main(cpu_id: usize) -> ! {
    kernel::arch::boot::seed(cpu_id, 0, kernel::arch::RawBootSource::DeviceTree);
    kernel::arch::cpu::set_current_id(cpu_id);
    kernel::arch::console::write_bytes(b"namenotfound qemu loongarch64 boot\n");
    let _ = kernel::init_all();
    kernel::arch::console::write_bytes(b"init_all returned\n");
    kernel::run_current_user();
}

#[cfg(target_arch = "loongarch64")]
#[panic_handler]
fn panic(_info: &core::panic::PanicInfo<'_>) -> ! {
    kernel::raw_panic()
}

