{
    . = PHYS_BASE;
    skernel = .;

    .boot.entry : ALIGN(4K) {
        KEEP(*(.boot.entry))
    }

    . = ALIGN(4K);
    . += PHYS_OFFSET;

    .text : AT(ADDR(.text) - PHYS_OFFSET) {
        KEEP(*(.text.entry))
        *(.text .text.*)
    }

    .rodata : ALIGN(4K) {
        *(.rodata .rodata.*)
    }

    .data : ALIGN(4K) {
        *(.data .data.*)
        *(.sdata .sdata.*)
        *(.got .got.*)
    }

    .bss : ALIGN(4K) {
        sbss = .;
        *(.bss .bss.*)
        *(.sbss .sbss.*)
        *(COMMON)
        ebss = .;
    }

    . = ALIGN(4K);
    bootstack = .;
    . += 0x10000;
    bootstacktop = .;

    . = ALIGN(4K);
    ekernel = .;

    /DISCARD/ : {
        *(.eh_frame_hdr)
        *(.eh_frame)
    }
